import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { RuleTranslationDetailsComponent } from './rule-translation-details/rule-translation-details.component';
import { RuleTranslationSummaryComponent } from './rule-translation-summary/rule-translation-summary.component';
import { RuleTranslationComponent } from './rule-translation/rule-translation.component';

const routes: Routes = [
  {
    path:'create',
    component:RuleTranslationComponent
  },{
    path:'edit/:id',
    component:RuleTranslationDetailsComponent
  },{
    path:'summary',
    component:RuleTranslationSummaryComponent
  }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class RuleTranslationRoutingModule { }
